-- Prompt 27 gym/date scoping, low-sample labels and staff-only privacy.
begin;set local role service_role;
insert into public.ascent_logs(gym_id,route_id,profile_id,ascent_type,attempts,climbed_at,session_date,visibility,route_colour_snapshot,route_grade_snapshot,route_grade_system_snapshot,wall_name_snapshot,notes)values('30000000-0000-4000-8000-000000000001','70000000-0000-4000-8000-000000000001','10000000-0000-4000-8000-000000000004','redpoint',2,now(),current_date,'private','Blue','6B','font','Main wall','Private beta note');
set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
do $$begin if exists(select 1 from public.get_route_setting_analytics('30000000-0000-4000-8000-000000000001',current_date-7,current_date,null,null,null))then raise exception'Member accessed staff analytics';end if;end$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);
do $$declare row record;begin select*into row from public.get_route_setting_analytics('30000000-0000-4000-8000-000000000001',current_date-7,current_date,null,null,null)where route_id='70000000-0000-4000-8000-000000000001';if row.route_id is null or row.activity_count<1 or row.send_count<1 or row.low_sample is not true then raise exception'Analytics did not reconcile or label low sample';end if;if exists(select 1 from public.get_route_setting_analytics('30000000-0000-4000-8000-000000000001',current_date-20,current_date-10,null,null,null)where activity_count>0)then raise exception'Date scope leaked activity';end if;if pg_get_function_result('public.get_route_setting_analytics(uuid,date,date,uuid,uuid,text)'::regprocedure)~'(profile_id|notes|comment)'then raise exception'Analytics result exposes personal fields';end if;end$$;
rollback;
